import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';

import { useAuth } from '../../context/AuthContext';
import { registerSchema } from '../../utils/validationSchemas';
import AuthLayout from '../../components/auth/AuthLayout';
import FormInput from '../../components/common/FormInput';
import PasswordStrengthMeter from '../../components/common/PasswordStrengthMeter';

const RegisterPage = () => {
  const navigate             = useNavigate();
  const { register: registerUser } = useAuth();

  const [serverError,  setServerError]  = useState('');
  const [successMsg,   setSuccessMsg]   = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  const {
    register,
    handleSubmit,
    watch,
    setError,
    formState: { errors },
  } = useForm({
    resolver: zodResolver(registerSchema),
    defaultValues: { role: 'customer', agreeToTerms: false },
  });

  const passwordValue = watch('password', '');
  const selectedRole  = watch('role');

  const onSubmit = async (data) => {
    setServerError('');
    setSuccessMsg('');
    setIsSubmitting(true);

    const payload = {
      firstName:       data.firstName,
      lastName:        data.lastName,
      email:           data.email,
      password:        data.password,
      confirmPassword: data.confirmPassword,
      role:            data.role,
      phone:           data.phone || undefined,
      agreeToTerms:    true,
    };

    const result = await registerUser(payload);
    setIsSubmitting(false);

    if (result.success) {
      setSuccessMsg(result.message || 'Account created! Please check your email to verify.');
    } else {
      // Show general error banner
      setServerError(result.message || 'Registration failed.');

      // Map field-level errors onto the form so they show inline under each field
      if (result.errors && Object.keys(result.errors).length > 0) {
        Object.entries(result.errors).forEach(([field, msg]) => {
          setError(field, { type: 'server', message: msg });
        });
      }
    }
  };

  // ── Success screen ─────────────────────────────────────────────────────────
  if (successMsg) {
    return (
      <AuthLayout>
        <div style={styles.successCard}>
          <div style={styles.successIcon}>✉️</div>
          <h2 style={styles.successTitle}>Check your inbox!</h2>
          <p style={styles.successBody}>{successMsg}</p>
          <p style={styles.successHint}>
            Didn't get the email?{' '}
            <button
              type="button"
              onClick={() => navigate('/auth/resend-verification')}
              style={styles.inlineLink}
            >
              Resend verification
            </button>
          </p>
          <Link to="/auth/login" style={styles.backBtn}>
            Back to Login
          </Link>
        </div>
      </AuthLayout>
    );
  }

  // ── Registration form ──────────────────────────────────────────────────────
  return (
    <AuthLayout
      title="Create your account"
      subtitle="Join PropMaintain to book or offer property services."
    >
      <form onSubmit={handleSubmit(onSubmit)} noValidate>

        {/* ── Role selector ── */}
        <div style={styles.roleRow}>
          {[
            { value: 'customer', label: '🔍 I need services',  sub: 'Find & book professionals' },
            { value: 'provider', label: '🔧 I offer services', sub: 'List & receive bookings'    },
          ].map(({ value, label, sub }) => (
            <label
              key={value}
              style={{
                ...styles.roleCard,
                ...(selectedRole === value ? styles.roleCardActive : {}),
              }}
            >
              <input type="radio" value={value} style={{ display: 'none' }} {...register('role')} />
              <span style={styles.roleLabel}>{label}</span>
              <span style={styles.roleSub}>{sub}</span>
            </label>
          ))}
        </div>
        {errors.role && <p style={styles.fieldError}>⚠ {errors.role.message}</p>}

        {/* ── Name row ── */}
        <div style={styles.nameRow}>
          <FormInput
            label="First Name"
            name="firstName"
            register={register}
            error={errors.firstName?.message}
            placeholder="Jane"
            required
            autoComplete="given-name"
          />
          <FormInput
            label="Last Name"
            name="lastName"
            register={register}
            error={errors.lastName?.message}
            placeholder="Smith"
            required
            autoComplete="family-name"
          />
        </div>

        {/* ── Email ── */}
        <FormInput
          label="Email Address"
          name="email"
          type="email"
          register={register}
          error={errors.email?.message}
          placeholder="jane@example.com"
          required
          autoComplete="email"
        />

        {/* ── Phone ── */}
        <FormInput
          label="Phone Number"
          name="phone"
          type="tel"
          register={register}
          error={errors.phone?.message}
          placeholder="+44 7700 900000"
          autoComplete="tel"
          hint="Optional – used for service notifications"
        />

        {/* ── Password ── */}
        <div style={styles.passwordSection}>
          <FormInput
            label="Password"
            name="password"
            type="password"
            register={register}
            error={errors.password?.message}
            placeholder="Create a strong password"
            required
            autoComplete="new-password"
          />
          <PasswordStrengthMeter password={passwordValue} />
        </div>

        {/* ── Confirm Password ── */}
        <FormInput
          label="Confirm Password"
          name="confirmPassword"
          type="password"
          register={register}
          error={errors.confirmPassword?.message}
          placeholder="Re-enter your password"
          required
          autoComplete="new-password"
        />

        {/* ── Terms checkbox ── */}
        <div style={styles.termsRow}>
          <label style={styles.checkboxLabel}>
            <input type="checkbox" style={styles.checkbox} {...register('agreeToTerms')} />
            <span style={styles.checkboxText}>
              I agree to the{' '}
              <Link to="/terms" style={styles.link}>Terms of Service</Link>
              {' '}and{' '}
              <Link to="/privacy" style={styles.link}>Privacy Policy</Link>
            </span>
          </label>
          {errors.agreeToTerms && (
            <p style={styles.fieldError}>⚠ {errors.agreeToTerms.message}</p>
          )}
        </div>

        {/* ── Server error banner (shown when email/phone already exists etc.) ── */}
        {serverError && (
          <div role="alert" style={styles.serverError}>
            ⚠ {serverError}
          </div>
        )}

        {/* ── Submit ── */}
        <button
          type="submit"
          disabled={isSubmitting}
          style={{ ...styles.submitBtn, ...(isSubmitting ? styles.submitBtnDisabled : {}) }}
        >
          {isSubmitting ? 'Creating account…' : 'Create Account'}
        </button>

        <p style={styles.loginPrompt}>
          Already have an account?{' '}
          <Link to="/auth/login" style={styles.link}>Sign in</Link>
